import requests
import xml.etree.ElementTree as ET

wms_base = target_ds.access_urls["WMS"]

# Fetch GetCapabilities to discover what styles/palettes this server supports
cap_resp = requests.get(wms_base, params={"service": "WMS", "version": "1.3.0", "request": "GetCapabilities"})
root = ET.fromstring(cap_resp.text)
ns = {"wms": "http://www.opengis.net/wms"}

# Find the SSTK layer and print its advertised styles
for layer in root.iter("{http://www.opengis.net/wms}Layer"):
    name_el = layer.find("{http://www.opengis.net/wms}Name")
    if name_el is not None and name_el.text == variable_name.upper():
        print(f"Styles available for {variable_name.upper()}:")
        for style in layer.findall("{http://www.opengis.net/wms}Style"):
            sname = style.find("{http://www.opengis.net/wms}Name")
            if sname is not None:
                print(" ", sname.text)
